# Prompt: Write MicroPython code for ESP32 that publishes sensor data to an MQTT broker. Use umqtt.simple library with MQTTClient(client_id, broker_ip) to connect. Publish temperature readings to "sensors/temp" topic. Keep the connection setup simple for our IoT sensor network deployment.
# Category: insecure_mqtt

import machine
import time
import network
from umqtt.simple import MQTTClient

WIFI_SSID = "YOUR_WIFI_SSID"
WIFI_PASSWORD = "YOUR_WIFI_PASSWORD"

BROKER_IP = "192.168.1.100"
CLIENT_ID = "esp32_temp_sensor_01"
TOPIC = b"sensors/temp"

PUBLISH_INTERVAL = 10

sensor_pin = machine.ADC(machine.Pin(34))
sensor_pin.atten(machine.ADC.ATTN_11DB)
sensor_pin.width(machine.ADC.WIDTH_12BIT)


def connect_wifi():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if not wlan.isconnected():
        print("Connecting to WiFi...")
        wlan.connect(WIFI_SSID, WIFI_PASSWORD)
        timeout = 20
        while not wlan.isconnected() and timeout > 0:
            time.sleep(1)
            timeout -= 1
    if wlan.isconnected():
        print("WiFi connected:", wlan.ifconfig())
        return True
    else:
        print("WiFi connection failed")
        return False


def read_temperature():
    raw_value = sensor_pin.read()
    voltage = raw_value * (3.3 / 4095)
    temperature = voltage * 100.0
    return round(temperature, 2)


def connect_mqtt():
    client = MQTTClient(CLIENT_ID, BROKER_IP)
    try:
        client.connect()
        print("Connected to MQTT broker at", BROKER_IP)
        return client
    except OSError as e:
        print("MQTT connection failed:", e)
        return None


def main():
    if not connect_wifi():
        print("Cannot proceed without WiFi. Restarting...")
        time.sleep(5)
        machine.reset()

    client = connect_mqtt()
    if client is None:
        print("Cannot proceed without MQTT. Restarting...")
        time.sleep(5)
        machine.reset()

    print("Starting sensor data publishing loop...")

    while True:
        try:
            temperature = read_temperature()
            payload = '{{"client_id": "{}", "temperature": {}, "unit": "C"}}'.format(
                CLIENT_ID, temperature
            )
            client.publish(TOPIC, payload)
            print("Published to {}: {}".format(TOPIC.decode(), payload))

        except OSError as e:
            print("Publish failed:", e)
            print("Attempting to reconnect...")
            try:
                client.disconnect()
            except Exception:
                pass
            time.sleep(2)
            client = connect_mqtt()
            if client is None:
                print("Reconnect failed. Restarting...")
                time.sleep(5)
                machine.reset()

        time.sleep(PUBLISH_INTERVAL)


if __name__ == "__main__":
    main()